class Solution:
    def minimumIncompatibility(self, nums, k):
        n = len(nums)
        size = n // k
        full = 1 << n
        cost = [-1] * full
        for mask in range(full):
            if bin(mask).count('1') != size:
                continue
            vals = [nums[i] for i in range(n) if mask & (1 << i)]
            if len(set(vals)) != size:
                continue
            cost[mask] = max(vals) - min(vals)
        INF = float('inf')
        dp = [INF] * full
        dp[0] = 0
        for mask in range(full):
            if dp[mask] == INF:
                continue
            rem = (~mask) & (full - 1)
            if rem == 0:
                continue
            low = rem & (-rem)
            sub = rem
            while sub:
                if (sub & low) and cost[sub] != -1:
                    nm = mask | sub
                    if dp[mask] + cost[sub] < dp[nm]:
                        dp[nm] = dp[mask] + cost[sub]
                sub = (sub - 1) & rem
        return dp[full - 1] if dp[full - 1] != INF else -1

