var minimumIncompatibility = function(nums, k) {
    const n = nums.length;
    const size = n / k;
    const full = 1 << n;
    const cost = new Array(full).fill(-1);
    for (let mask = 0; mask < full; mask++) {
        let bits = 0;
        for (let b = 0; b < n; b++) if (mask & (1 << b)) bits++;
        if (bits !== size) continue;
        const seen = new Set();
        let mn = Infinity, mx = -Infinity;
        let dup = false;
        for (let b = 0; b < n; b++) {
            if (mask & (1 << b)) {
                if (seen.has(nums[b])) { dup = true; break; }
                seen.add(nums[b]);
                mn = Math.min(mn, nums[b]);
                mx = Math.max(mx, nums[b]);
            }
        }
        if (!dup) cost[mask] = mx - mn;
    }
    const INF = Infinity;
    const dp = new Array(full).fill(INF);
    dp[0] = 0;
    for (let mask = 0; mask < full; mask++) {
        if (dp[mask] === INF) continue;
        const rem = (~mask) & (full - 1);
        if (rem === 0) continue;
        const low = rem & (-rem);
        let sub = rem;
        while (sub) {
            if ((sub & low) && cost[sub] !== -1) {
                const nm = mask | sub;
                if (dp[mask] + cost[sub] < dp[nm]) dp[nm] = dp[mask] + cost[sub];
            }
            sub = (sub - 1) & rem;
        }
    }
    return dp[full - 1] === INF ? -1 : dp[full - 1];
};
